def custom_cross_validate(X, y, n_folds=5, random_state=42):
    """
    Custom cross-validation implementation.
    Fallback if tools function fails.
    """
    kfold = KFold(n_splits=n_folds, shuffle=True, random_state=random_state)
    
    cv_results = []
    r2_scores = []
    mse_scores = []
    
    for fold, (train_idx, test_idx) in enumerate(kfold.split(X)):
        try:
            # Split data
            X_train, X_test = X[train_idx], X[test_idx]
            y_train, y_test = y[train_idx], y[test_idx]
            
            # Fit model on training set
            X_train_intercept = sm.add_constant(X_train)
            train_model = sm.OLS(y_train, X_train_intercept).fit()
            
            # Predict on test set
            X_test_intercept = sm.add_constant(X_test)
            y_pred = train_model.predict(X_test_intercept)
            
            # Calculate metrics
            r2_cv = r2_score(y_test, y_pred)
            mse_cv = mean_squared_error(y_test, y_pred)
            
            cv_results.append({
                'fold': fold + 1,
                'r_squared_cv': r2_cv,
                'mse_cv': mse_cv,
                'n_train': len(X_train),
                'n_test': len(X_test),
                'train_r2': train_model.rsquared,
                'test_r2': r2_cv
            })
            
            r2_scores.append(r2_cv)
            mse_scores.append(mse_cv)
            
            log(f"[FOLD {fold+1}] R²_CV = {r2_cv:.4f}, MSE_CV = {mse_cv:.4f}")
            
        except Exception as e:
            log(f"[WARNING] Cross-validation fold {fold+1} failed: {str(e)}")
            cv_results.append({
                'fold': fold + 1,
                'r_squared_cv': np.nan,
                'mse_cv': np.nan,
                'n_train': len(X_train) if 'X_train' in locals() else np.nan,
                'n_test': len(X_test) if 'X_test' in locals() else np.nan,
                'train_r2': np.nan,
                'test_r2': np.nan
            })
    
    # Calculate summary statistics
    valid_r2_scores = [r for r in r2_scores if not np.isnan(r)]
    valid_mse_scores = [mse for mse in mse_scores if not np.isnan(mse)]
    
    if len(valid_r2_scores) > 0:
        mean_cv_r2 = np.mean(valid_r2_scores)
        se_cv_r2 = np.std(valid_r2_scores) / np.sqrt(len(valid_r2_scores))
        mean_cv_mse = np.mean(valid_mse_scores)
        se_cv_mse = np.std(valid_mse_scores) / np.sqrt(len(valid_mse_scores))
    else:
        mean_cv_r2 = np.nan
        se_cv_r2 = np.nan
        mean_cv_mse = np.nan
        se_cv_mse = np.nan
    
    # Add summary statistics to each fold result
    for result in cv_results:
        result['mean_cv_r_squared'] = mean_cv_r2
        result['se_cv_r_squared'] = se_cv_r2
        result['mean_cv_mse'] = mean_cv_mse
        result['se_cv_mse'] = se_cv_mse
    
    return {
        'cv_results': cv_results,
        'mean_r2': mean_cv_r2,
        'se_r2': se_cv_r2,
        'mean_mse': mean_cv_mse,
        'se_mse': se_cv_mse,
        'successful_folds': len(valid_r2_scores)
    }

def interpret_cv_performance(mean_r2, se_r2, n_folds):
    """
    Interpret cross-validation performance.
    """
    if np.isnan(mean_r2):
        return "Indeterminate (CV failed)"
    
    # Calculate 95% confidence interval for CV R²
    ci_lower = mean_r2 - 1.96 * se_r2
    ci_upper = mean_r2 + 1.96 * se_r2
    
    # Interpret performance
    if mean_r2 >= 0.25:
        performance = "Good"
    elif mean_r2 >= 0.10:
        performance = "Moderate"  
    elif mean_r2 >= 0.05:
        performance = "Weak"
    else:
        performance = "Poor"
    
    # Check stability (narrow CI relative to mean)
    if se_r2 / mean_r2 < 0.2:  # CV < 20%
        stability = "Stable"
    elif se_r2 / mean_r2 < 0.5:
        stability = "Moderately stable"
    else:
        stability = "Unstable"
    
    return f"{performance} generalization ({stability}), 95% CI [{ci_lower:.3f}, {ci_upper:.3f}]"

